So the "correct" way to fix this will be coming in a future patch but requires some internal changes. That said, you can do some gymnastics... try this out (sorry about the spaghetti code -- this is just a quick fix and should be cleaned up):

* Edit: realized I left out some things
```dart
import 'package:flutter/material.dart';
import 'package:flutter/scheduler.dart';

void main(List<String> args) {
  runApp(const ExampleApp());
}

class ExampleApp extends StatefulWidget {
  const ExampleApp({super.key});

  @override
  State<ExampleApp> createState() => _ExampleAppState();
}

class _ExampleAppState extends State<ExampleApp> {
  List<FocusNode> firstItemFocusNodes =
      List.generate(3, (index) => FocusNode());

  @override
  void dispose() {
    for (final node in firstItemFocusNodes) {
      node.dispose();
    }

    super.dispose();
  }

  @override
  Widget build(BuildContext context) {
    final content = Column(
      children: [
        for (int i = 0; i < 3; i++)
          _DropdownMenu(
            menuItems: [
              for (int j = 0; j < 3; j++)
                MenuItemButton(
                  focusNode: j == 0 ? firstItemFocusNodes[i] : null,
                  child: Text("$i - $j"),
                  onPressed: () {},
                ),
            ],
            trailingIcon: IconButton(
              onPressed: () {},
              icon: const Icon(Icons.clear),
            ),
            firstItemFocusNode: firstItemFocusNodes[i],
            child: Text("Dropdown menu $i"),
          ),
      ],
    );

    return MaterialApp(
      home: Scaffold(
        appBar: AppBar(
          title: const Text("Focus Experiments"),
        ),
        body: SafeArea(
          minimum: const EdgeInsets.all(16),
          child: content,
        ),
      ),
    );
  }
}

/// A custom implementation bridging the gap between a [DropdownMenu] and a
/// [DropdownButton]
class _DropdownMenu extends StatefulWidget {
  const _DropdownMenu({
    required this.menuItems,
    this.trailingIcon,
    required this.child,
    required this.firstItemFocusNode,
  });

  final List<Widget> menuItems;
  final Widget? trailingIcon;
  final Widget child;
  final FocusNode firstItemFocusNode;

  @override
  State<_DropdownMenu> createState() => _DropdownMenuState();
}

class _DropdownMenuState extends State<_DropdownMenu> {
  final _controller = WidgetStatesController();
  final _menuController = MenuController();
  final _childNode = FocusNode(debugLabel: "Dropdown Inkwell");
  final _focusWrapperNode = FocusNode(debugLabel: "Dropdown Focus Node");

  late final _actions = <Type, Action<Intent>>{
    DirectionalFocusIntent: _DirectionalFocusMenuAction(this),
    NextFocusIntent: _NextFocusMenuAction(this),
  };

  @override
  void dispose() {
    _controller.dispose();
    _childNode.dispose();
    _focusWrapperNode.dispose();
    super.dispose();
  }

  void _handleTap() {
    if (!_menuController.isOpen) {
      _menuController.open();
      SchedulerBinding.instance.addPostFrameCallback((timeStamp) {
        FocusScope.of(context).setFirstFocus(
          widget.firstItemFocusNode.nearestScope!,
        );
        _childNode.requestFocus();
      });
    } else {
      _menuController.close();
    }
  }

  @override
  Widget build(BuildContext context) {
    return Focus(
      focusNode: _focusWrapperNode,
      onFocusChange: _handleFocusChange,
      canRequestFocus: false,
      skipTraversal: true,
      includeSemantics: false,
      child: MenuAnchor(
        controller: _menuController,
        childFocusNode: _childNode,
        style: const MenuStyle(
          padding: WidgetStatePropertyAll(
              EdgeInsets.symmetric(vertical: 8, horizontal: 16)),
        ),
        builder: (context, controller, child) {
          return Actions(
            actions: _actions,
            child: InkWell(
              focusNode: _childNode,
              statesController: _controller,
              borderRadius:
                  const BorderRadius.vertical(top: Radius.circular(8)),
              onTap: _handleTap,
              child: ListenableBuilder(
                listenable: _controller,
                builder: (context, _) {
                  return InputDecorator(
                    decoration:
                        const InputDecoration(border: UnderlineInputBorder()),
                    isFocused: _controller.value.contains(WidgetState.focused),
                    isHovering: _controller.value.contains(WidgetState.hovered),
                    child: Row(
                      children: [
                        Expanded(
                          child: DefaultTextStyle(
                            style:
                                Theme.of(context).dropdownMenuTheme.textStyle ??
                                    Theme.of(context).textTheme.bodyLarge!,
                            child: child!,
                          ),
                        ),
                        if (widget.trailingIcon != null) widget.trailingIcon!,
                      ],
                    ),
                  );
                },
              ),
            ),
          );
        },
        menuChildren: widget.menuItems,
        child: widget.child,
      ),
    );
  }

  void _handleFocusChange(bool value) {
    if (!_focusWrapperNode.hasFocus) {
      _menuController.close();
    }
  }
}

class _DirectionalFocusMenuAction extends DirectionalFocusAction {
  _DirectionalFocusMenuAction(this.state);
  final _DropdownMenuState state;

  @override
  bool invoke(DirectionalFocusIntent intent) {
    if (intent.direction
        case TraversalDirection.right || TraversalDirection.left) {
      super.invoke(intent);
      return true;
    }

    if (state._menuController.isOpen && state._childNode.hasFocus) {
      final context = state.widget.firstItemFocusNode.context;
      if (context?.mounted != true) {
        return false;
      }
      final FocusTraversalPolicy policy =
          FocusTraversalGroup.maybeOf(context!) ??
              ReadingOrderTraversalPolicy();

      FocusNode? nextFocus;
      if (intent.direction == TraversalDirection.up) {
        nextFocus = policy.findLastFocus(
          state.widget.firstItemFocusNode,
          ignoreCurrentFocus: true,
        );
      } else {
        nextFocus = policy.findFirstFocus(
          state.widget.firstItemFocusNode,
          ignoreCurrentFocus: true,
        );
      }
      nextFocus?.requestFocus();
    } else {
      super.invoke(intent);
    }
    return true;
  }
}

class _NextFocusMenuAction extends NextFocusAction {
  _NextFocusMenuAction(this.state);
  final _DropdownMenuState state;

  @override
  bool invoke(NextFocusIntent intent) {
    if (state._childNode.hasFocus && state._menuController.isOpen) {
      state.widget.firstItemFocusNode.requestFocus();
      return true;
    }
    return super.invoke(intent);
  }
}

```

