class _MyHomePageState extends State<MyHomePage> {
  @override
  Widget build(BuildContext context) {
    return MaterialApp(
      initialRoute: "/home",
      routes: {
        "/home": (context) => const NewWidget(),
      },
      home: const NewWidget(), // < comment this out and the exception does not occurr
