### Steps to reproduce

1. Change keyboard to "Japanese - Kana" and disable "Live conversion":
 ![Screenshot 2024-01-16 at 10 12 27](https://github.com/superlistapp/super_editor/assets/31278849/8fb8d5cb-ed17-49a8-bad4-a360aac13048)
2. Run the sample code on macOS
3. Type querty
4. Pick the suggestion from the popover list 

### Expected results

Conversion takes place and the content is replaced.

### Actual results

An invalid character is reported when pressing the down arrow to select the suggestion and its maintained after picking the selection.

### Code sample

<details><summary>Code sample</summary>

```dart
import 'package:flutter/material.dart';
import 'package:flutter/services.dart';

void main() {
  runApp(
    const MaterialApp(
      home: Scaffold(
        body: TextInputExample(),
      ),
    ),
  );
}

class TextInputExample extends StatefulWidget {
  const TextInputExample({super.key});

  @override
  State<TextInputExample> createState() => _TextInputExampleState();
}

class _TextInputExampleState extends State<TextInputExample> implements DeltaTextInputClient {
  final FocusNode _focusNode = FocusNode();
  final GlobalKey _textKey = GlobalKey();

  TextInputConnection? _inputConnection;
  TextEditingValue _currentEditingValue = const TextEditingValue(
    text: 'Type "querty" and pick the option on the popover: ',
    selection: TextSelection.collapsed(offset: 49),
  );

  @override
  void initState() {
    super.initState();
    WidgetsBinding.instance.addPostFrameCallback((timeStamp) {
      _attach();
      _reportVisualInformationToIme();
    });
  }

  @override
  void dispose() {
    _focusNode.dispose();
    super.dispose();
  }

  @override
  void updateEditingValueWithDeltas(List<TextEditingDelta> textEditingDeltas) {
    print('Received ${textEditingDeltas.length} deltas');
    TextEditingValue newEditingValue = _currentEditingValue;

    for (final delta in textEditingDeltas) {
      print(delta);
      newEditingValue = delta.apply(newEditingValue);
    }

    setState(() {
      _currentEditingValue = newEditingValue;
    });
  }

  void _attach() {
    if (_inputConnection != null) {
      return;
    }
    _inputConnection = TextInput.attach(
      this,
      const TextInputConfiguration(
        enableDeltaModel: true,
        inputType: TextInputType.multiline,
        textCapitalization: TextCapitalization.sentences,
        inputAction: TextInputAction.newline,
        keyboardAppearance: Brightness.light,
      ),
    );
    _inputConnection!.show();
    _inputConnection!.setEditingState(_currentEditingValue);
  }

  KeyEventResult _onKeyEvent(FocusNode node, KeyEvent event) {
    // Let the OS handle the keys.
    return KeyEventResult.skipRemainingHandlers;
  }

  void _reportVisualInformationToIme() {
    final myRenderBox = context.findRenderObject() as RenderBox?;
    if (myRenderBox != null && myRenderBox.hasSize) {
      _reportSizeAndTransformToIme();
      _reportCaretRectToIme();
    }
  }

  void _reportSizeAndTransformToIme() {
    final renderBox = _textKey.currentContext!.findRenderObject() as RenderBox;

    final size = renderBox.size;
    final transform = renderBox.getTransformTo(null);

    _inputConnection!.setEditableSizeAndTransform(size, transform);
  }

  void _reportCaretRectToIme() {
    _inputConnection!.setCaretRect(Rect.zero);
  }

  @override
  Widget build(BuildContext context) {
    return Center(
      child: Focus(
        focusNode: _focusNode,
        autofocus: true,
        onKeyEvent: _onKeyEvent,
        child: DecoratedBox(
          decoration: BoxDecoration(border: Border.all()),
          child: Text(
            key: _textKey,
            _currentEditingValue.text,
            textAlign: TextAlign.center,
          ),
        ),
      ),
    );
  }

  @override
  void connectionClosed() {}

  @override
